package org.jsoup.helper;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.helper.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.helper.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.jsoup.helper.DataUtil;

public class StepDefs {
    private String header;
    private String result;

    @Given("the Content-Type header is {string}")
    public void given_the_content_type_header_is(String header) {
        this.header = header;
    }

    @When("the charset is extracted")
    public void when_the_charset_is_extracted() {
        try {
            // Using DataUtil to extract charset - this is where the bug occurs
            result = DataUtil.getCharsetFromContentType(header);
        } catch (Exception e) {
            result = null; // In case of any exception, return null
        }
    }

    @Then("the result should be {string}")
    public void then_the_result_should_be(String expected) {
        assertEquals(expected, result);
    }

    @Then("the result should be null")
    public void then_the_result_should_be_null() {
        assertNull(result);
    }
}

